/* GNN Architectures from gnn_collapse/models/graphconv.py */

class GraphConv(MessagePassing):
    def __init__(self, in_channels, out_channels, use_W1, bias=False, aggr='mean', **kwargs):
        super().__init__(aggr=aggr, **kwargs)
        # ... (initialization)
        # W2 weights (message passing term)
        self.lin_rel = Linear(in_channels[0], out_channels, bias=bias)
        # W1 weights (identity connection term)
        if self.use_W1:
            self.lin_root = Linear(in_channels[1], out_channels, bias=bias)
        self.reset_parameters()

    def forward(self, x: Union[Tensor, OptPairTensor], edge_index: Adj,
                edge_weight: OptTensor = None, size: Size = None) -> Tensor:
        # ... (propagate and aggregate)
        out = self.propagate(edge_index, x=x, edge_weight=edge_weight,
                             size=size)
        out = self.lin_rel(out)
        # Add identity connection if use_W1 is True
        if self.use_W1:
            x_r = x[1]
            if x_r is not None:
                out = out + self.lin_root(x_r)
        return out

